insert into public.chapters (id,world_id,name,sort,is_free,published,version,description,intro,boss_name,boss_description) values
  ('culture-heritage','culture','文化拾遗',2,true,true,1,'节俗、典故、书画、戏曲与语用常识 · 20 道训练题','从一个节日、一件乐器、一部作品开始，把文化记忆串成网络。','文脉寻珍试炼','在人物、作品、节俗和艺术形式之间找出准确对应。')
insert into public.levels (id,chapter_id,name,kind,sort,pass_score,reward_xp,published,version,summary) values
  ('culture-heritage-1','culture-heritage','2-1 节俗与典故','lesson',1,60,0,true,1,'节日、年龄称谓与诚信典故'),
  ('culture-heritage-2','culture-heritage','2-2 艺术与器物','lesson',2,60,0,true,1,'书画、戏曲、乐器与文化遗产'),
  ('culture-heritage-boss','culture-heritage','2-3 Boss · 文脉寻珍','boss',3,60,0,true,1,'综合辨析称谓、作品、人物与艺术形式')
insert into public.knowledge_points (id,name,summary,core_fact,category,common_mistake,memory_tip,published,version) values
  ('culture-festivals','传统节日','传统节日的农历日期与核心习俗是文化常识的基础。','春节为农历正月初一，元宵节为正月十五，端午节为五月初五，中秋节为八月十五，重阳节为九月初九。','传统节俗','把节日日期、农历月份或节日习俗错配。','一春二元三清四端五中六重阳。',true,1),
  ('culture-yinuo-origin','一诺千金典故','一诺千金出自《史记·季布栾布列传》，主人公为季布。','“得黄金百斤，不如得季布一诺”赞扬守信重诺。','典故与诚信','把季布与季札挂剑、尾生抱柱等守信典故混淆。','一诺千金记季布，核心就是重承诺。',true,1),
  ('culture-wudaozi','吴道子','唐代画家吴道子以人物画著称，后世尊为“画圣”。','吴道子被称为“画圣”。','书画艺术','把吴道子与书法家、诗人或其他画家称号混淆。','吴道子，画圣。',true,1),
  ('culture-zenghouyi','曾侯乙编钟','曾侯乙编钟是先秦礼乐文化和古代音乐成就的重要实物。','曾侯乙编钟出土于湖北随州的曾侯乙墓。','器物与音乐','把曾侯乙编钟的时代、出土地或文化价值混淆。','编钟看曾侯乙，湖北随州出土。',true,1),
  ('culture-calligraphy','书法演变','书法在不同历史时期形成各具特点的书体与代表人物。','秦朝统一小篆；王羲之以《兰亭集序》著名；颜真卿是唐代书法家。','书法艺术','把小篆、隶书、行书与相关时代、人物混淆。','秦统一小篆，兰亭看王羲之，唐楷有颜真卿。',true,1),
  ('culture-opera','中国戏曲','戏曲的剧种、行当与表演程式构成中国传统舞台艺术的重要内容。','京剧四大行当为生、旦、净、丑；昆曲被誉为“百戏之祖”。','戏曲艺术','把京剧行当、昆曲地位和地方剧种混淆。','京剧生旦净丑，昆曲百戏之祖。',true,1),
  ('culture-instruments','民族乐器','民族乐器与民族、地域和表演传统具有稳定关联。','马头琴是蒙古族代表性乐器；芦笙与苗族、侗族文化密切相关。','民族艺术','把马头琴、芦笙与民族对应关系记串。','马头琴看蒙古，芦笙想苗侗。',true,1),
  ('culture-age-terms','古代年龄称谓','古代年龄称谓常按人生阶段表达，是言语文化常识的高频点。','弱冠指男子二十岁；而立三十岁；不惑四十岁；知天命五十岁；花甲六十岁；古稀七十岁。','语言文化','把不惑、知天命、花甲等年龄前后错位。','二十弱冠三十立，四十不惑五十命，花甲六十古稀七十。',true,1),
  ('culture-honorifics','谦辞与敬辞','谦辞多用于称己方，敬辞多用于称对方或对方相关事物。','家父、拙见是谦辞；令尊、高见是敬辞。','语言文化','把“家”“舍”“拙”类与“令”“高”“惠”类用反。','家舍拙称己，令高惠敬人。',true,1),
  ('culture-four-novels','四大名著','四大名著的作品与作者对应是中国古典文学的基础常识。','《西游记》通常署为吴承恩，《水浒传》通常署为施耐庵，《红楼梦》通常署为曹雪芹。','古典文学','将作品作者横向错配。','西游吴、水浒施、红楼曹。',true,1)
