insert into public.questions (id,knowledge_id,level_id,question_type,stem,options,correct_answer,explanation,difficulty,published,version) values
  ('culture-heritage-01','culture-festivals','culture-heritage-1','single_choice','端午节的农历日期是？','{"questionId":"culture-heritage-01","knowledgeId":"culture-festivals","type":"single_choice","stem":"端午节的农历日期是？","options":[{"id":"A","text":"五月初五"},{"id":"B","text":"正月十五"},{"id":"C","text":"八月十五"},{"id":"D","text":"九月初九"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：五月初五","whyCorrect":"端午节在农历五月初五，常见习俗包括赛龙舟、吃粽子等。","whyUserAnswerWrong":"元宵节是正月十五，中秋节是八月十五，重阳节是九月初九。","commonMistake":"把多个带“十五”“初九”的节日日期混淆。","memoryTip":"端午五月初五。"}'::jsonb,1,true,1),
  ('culture-heritage-02','culture-festivals','culture-heritage-1','single_choice','下列节日与农历日期对应正确的是？','{"questionId":"culture-heritage-02","knowledgeId":"culture-festivals","type":"single_choice","stem":"下列节日与农历日期对应正确的是？","options":[{"id":"A","text":"元宵节—正月初一"},{"id":"B","text":"中秋节—八月十五"},{"id":"C","text":"重阳节—五月初五"},{"id":"D","text":"春节—九月初九"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：中秋节—八月十五","whyCorrect":"中秋节在农历八月十五。","whyUserAnswerWrong":"元宵节为正月十五，重阳节为九月初九，春节为正月初一。","commonMistake":"将月圆的中秋与元宵日期混为同一节日。","memoryTip":"元宵正月十五，中秋八月十五。"}'::jsonb,2,true,1),
  ('culture-heritage-03','culture-yinuo-origin','culture-heritage-1','single_choice','“一诺千金”典故的主人公是？','{"questionId":"culture-heritage-03","knowledgeId":"culture-yinuo-origin","type":"single_choice","stem":"“一诺千金”典故的主人公是？","options":[{"id":"A","text":"季札"},{"id":"B","text":"尾生"},{"id":"C","text":"季布"},{"id":"D","text":"荆轲"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：季布","whyCorrect":"“得黄金百斤，不如得季布一诺”出自《史记·季布栾布列传》。","whyUserAnswerWrong":"季札挂剑、尾生抱柱也与守信有关，但不是一诺千金的典故。","commonMistake":"把相近的守信故事只按主题记忆，不记人物。","memoryTip":"一诺千金记季布。"}'::jsonb,2,true,1),
  ('culture-heritage-04','culture-age-terms','culture-heritage-1','single_choice','“不惑之年”通常指多少岁？','{"questionId":"culture-heritage-04","knowledgeId":"culture-age-terms","type":"single_choice","stem":"“不惑之年”通常指多少岁？","options":[{"id":"A","text":"三十岁"},{"id":"B","text":"四十岁"},{"id":"C","text":"五十岁"},{"id":"D","text":"六十岁"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：四十岁","whyCorrect":"“三十而立，四十而不惑，五十而知天命”。","whyUserAnswerWrong":"三十、四十、五十是一组连续称谓，应按顺序记。","commonMistake":"把不惑与知天命的年龄互换。","memoryTip":"三十立，四十不惑，五十知命。"}'::jsonb,1,true,1),
  ('culture-heritage-05','culture-age-terms','culture-heritage-1','single_choice','“花甲”通常指多少岁？','{"questionId":"culture-heritage-05","knowledgeId":"culture-age-terms","type":"single_choice","stem":"“花甲”通常指多少岁？","options":[{"id":"A","text":"五十岁"},{"id":"B","text":"六十岁"},{"id":"C","text":"七十岁"},{"id":"D","text":"八十岁"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：六十岁","whyCorrect":"六十年为一甲子，因此六十岁称花甲。","whyUserAnswerWrong":"古稀通常指七十岁，不要与花甲混淆。","commonMistake":"将“花甲”和“古稀”相邻但不同的称谓记反。","memoryTip":"花甲六十，古稀七十。"}'::jsonb,1,true,1),
  ('culture-heritage-06','culture-honorifics','culture-heritage-1','single_choice','下列词语中，属于敬辞的是？','{"questionId":"culture-heritage-06","knowledgeId":"culture-honorifics","type":"single_choice","stem":"下列词语中，属于敬辞的是？","options":[{"id":"A","text":"家父"},{"id":"B","text":"拙见"},{"id":"C","text":"令尊"},{"id":"D","text":"鄙人"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：令尊","whyCorrect":"“令尊”用于尊称对方的父亲，属于敬辞。","whyUserAnswerWrong":"家父、拙见、鄙人均用于称己方或自称，属于谦辞语境。","commonMistake":"不分说话对象，只按词义猜测谦敬。","memoryTip":"家舍拙称己，令高惠敬人。"}'::jsonb,2,true,1),
  ('culture-heritage-07','culture-wudaozi','culture-heritage-2','single_choice','被后世称为“画圣”的唐代画家是？','{"questionId":"culture-heritage-07","knowledgeId":"culture-wudaozi","type":"single_choice","stem":"被后世称为“画圣”的唐代画家是？","options":[{"id":"A","text":"吴道子"},{"id":"B","text":"王羲之"},{"id":"C","text":"颜真卿"},{"id":"D","text":"顾恺之"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：吴道子","whyCorrect":"吴道子以人物画著称，后世尊为“画圣”。","whyUserAnswerWrong":"王羲之、颜真卿以书法闻名，顾恺之是东晋画家。","commonMistake":"把书法家与画家称号交叉记忆。","memoryTip":"吴道子，画圣。"}'::jsonb,1,true,1),
  ('culture-heritage-08','culture-zenghouyi','culture-heritage-2','single_choice','曾侯乙编钟出土于哪里？','{"questionId":"culture-heritage-08","knowledgeId":"culture-zenghouyi","type":"single_choice","stem":"曾侯乙编钟出土于哪里？","options":[{"id":"A","text":"陕西西安"},{"id":"B","text":"湖北随州"},{"id":"C","text":"河南安阳"},{"id":"D","text":"四川成都"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：湖北随州","whyCorrect":"曾侯乙编钟出土于湖北随州曾侯乙墓，是古代礼乐文明的重要实物。","whyUserAnswerWrong":"安阳常与殷墟和甲骨文相关，其他地点也有重要文物但不对应本题。","commonMistake":"只记住编钟而忽略出土地。","memoryTip":"编钟看曾侯乙，湖北随州出土。"}'::jsonb,2,true,1),
  ('culture-heritage-09','culture-calligraphy','culture-heritage-2','single_choice','秦朝统一文字后推行的标准字体是？','{"questionId":"culture-heritage-09","knowledgeId":"culture-calligraphy","type":"single_choice","stem":"秦朝统一文字后推行的标准字体是？","options":[{"id":"A","text":"小篆"},{"id":"B","text":"楷书"},{"id":"C","text":"行书"},{"id":"D","text":"草书"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：小篆","whyCorrect":"秦朝统一文字，以小篆作为规范字体。","whyUserAnswerWrong":"楷、行、草书在后世发展成熟，不能放到秦朝统一文字的语境。","commonMistake":"把书体成熟的时代与文字统一的时代混淆。","memoryTip":"秦统一，小篆。"}'::jsonb,2,true,1),
  ('culture-heritage-10','culture-calligraphy','culture-heritage-2','single_choice','《兰亭集序》与哪位书法家对应？','{"questionId":"culture-heritage-10","knowledgeId":"culture-calligraphy","type":"single_choice","stem":"《兰亭集序》与哪位书法家对应？","options":[{"id":"A","text":"颜真卿"},{"id":"B","text":"王羲之"},{"id":"C","text":"欧阳询"},{"id":"D","text":"柳公权"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：王羲之","whyCorrect":"《兰亭集序》是王羲之的代表作，常被视为行书名作。","whyUserAnswerWrong":"颜真卿、欧阳询、柳公权均以唐代书法闻名，但不对应《兰亭集序》。","commonMistake":"只记住“书法名家”而未把作品锁定到作者。","memoryTip":"兰亭看王羲之。"}'::jsonb,2,true,1),
  ('culture-heritage-11','culture-opera','culture-heritage-2','single_choice','京剧的四大行当是？','{"questionId":"culture-heritage-11","knowledgeId":"culture-opera","type":"single_choice","stem":"京剧的四大行当是？","options":[{"id":"A","text":"生、旦、净、丑"},{"id":"B","text":"宫、商、角、徵"},{"id":"C","text":"吹、拉、弹、打"},{"id":"D","text":"起、承、转、合"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：生、旦、净、丑","whyCorrect":"生、旦、净、丑是京剧基本行当分类。","whyUserAnswerWrong":"其余选项分别属于音律、演奏或文章结构范畴。","commonMistake":"把京剧行当与戏曲表演四功混淆。","memoryTip":"京剧生旦净丑。"}'::jsonb,1,true,1),
  ('culture-heritage-12','culture-opera','culture-heritage-2','single_choice','被誉为“百戏之祖”的剧种是？','{"questionId":"culture-heritage-12","knowledgeId":"culture-opera","type":"single_choice","stem":"被誉为“百戏之祖”的剧种是？","options":[{"id":"A","text":"京剧"},{"id":"B","text":"昆曲"},{"id":"C","text":"豫剧"},{"id":"D","text":"越剧"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：昆曲","whyCorrect":"昆曲对后世众多剧种发展产生重要影响，常被誉为“百戏之祖”。","whyUserAnswerWrong":"京剧影响广泛，但“百戏之祖”是昆曲的常见称誉。","commonMistake":"将京剧的代表性与昆曲的历史地位混为一谈。","memoryTip":"昆曲百戏之祖。"}'::jsonb,2,true,1),
  ('culture-heritage-13','culture-instruments','culture-heritage-2','single_choice','马头琴是哪个民族的代表性乐器？','{"questionId":"culture-heritage-13","knowledgeId":"culture-instruments","type":"single_choice","stem":"马头琴是哪个民族的代表性乐器？","options":[{"id":"A","text":"蒙古族"},{"id":"B","text":"苗族"},{"id":"C","text":"朝鲜族"},{"id":"D","text":"维吾尔族"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：蒙古族","whyCorrect":"马头琴是蒙古族富有代表性的拉弦乐器。","whyUserAnswerWrong":"芦笙与苗族、侗族文化关系更密切。","commonMistake":"把少数民族乐器只按地域模糊记忆。","memoryTip":"马头琴看蒙古。"}'::jsonb,1,true,1),
  ('culture-heritage-14','culture-instruments','culture-heritage-2','single_choice','下列乐器与民族对应正确的是？','{"questionId":"culture-heritage-14","knowledgeId":"culture-instruments","type":"single_choice","stem":"下列乐器与民族对应正确的是？","options":[{"id":"A","text":"芦笙—苗族、侗族"},{"id":"B","text":"马头琴—苗族"},{"id":"C","text":"编钟—蒙古族"},{"id":"D","text":"古筝—藏族专属乐器"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：芦笙—苗族、侗族","whyCorrect":"芦笙是苗族、侗族等民族文化中具有代表性的乐器。","whyUserAnswerWrong":"马头琴对应蒙古族；编钟是古代礼乐器物，不是民族专属乐器。","commonMistake":"将“代表性乐器”误解为唯一归属。","memoryTip":"芦笙想苗侗。"}'::jsonb,2,true,1),
  ('culture-heritage-15','culture-four-novels','culture-heritage-boss','single_choice','下列作品与作者对应正确的是？','{"questionId":"culture-heritage-15","knowledgeId":"culture-four-novels","type":"single_choice","stem":"下列作品与作者对应正确的是？","options":[{"id":"A","text":"《西游记》—吴承恩"},{"id":"B","text":"《水浒传》—曹雪芹"},{"id":"C","text":"《红楼梦》—施耐庵"},{"id":"D","text":"《三国演义》—蒲松龄"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：《西游记》—吴承恩","whyCorrect":"《西游记》通常署为吴承恩；《水浒传》通常署为施耐庵，《红楼梦》通常署为曹雪芹。","whyUserAnswerWrong":"四大名著题应同时核对书名和作者，不要只记其中一个。","commonMistake":"把施耐庵、曹雪芹和吴承恩交叉错配。","memoryTip":"西游吴、水浒施、红楼曹。"}'::jsonb,2,true,1),
  ('culture-heritage-16','culture-honorifics','culture-heritage-boss','single_choice','下列用语使用恰当的是？','{"questionId":"culture-heritage-16","knowledgeId":"culture-honorifics","type":"single_choice","stem":"下列用语使用恰当的是？","options":[{"id":"A","text":"向对方介绍自己的父亲时说“令尊”"},{"id":"B","text":"称赞对方的见解时说“拙见高明”"},{"id":"C","text":"询问对方父亲时说“令尊身体可好”"},{"id":"D","text":"称自己的看法时说“高见如下”"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：询问对方父亲时说“令尊身体可好”","whyCorrect":"“令尊”是敬称，用于称对方父亲。","whyUserAnswerWrong":"介绍自己的父亲应说家父；称自己的见解应说拙见；“高见”用于尊称对方见解。","commonMistake":"忽略说话对象，导致谦辞敬辞方向反转。","memoryTip":"家舍拙称己，令高惠敬人。"}'::jsonb,3,true,1),
  ('culture-heritage-17','culture-yinuo-origin','culture-heritage-boss','single_choice','“一诺千金”最准确的文化内涵是？','{"questionId":"culture-heritage-17","knowledgeId":"culture-yinuo-origin","type":"single_choice","stem":"“一诺千金”最准确的文化内涵是？","options":[{"id":"A","text":"重视承诺与信用"},{"id":"B","text":"崇尚财富积累"},{"id":"C","text":"强调军事谋略"},{"id":"D","text":"赞美辞藻华丽"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：重视承诺与信用","whyCorrect":"一诺千金比喻说话算数、信用极高，强调诚信价值。","whyUserAnswerWrong":"“千金”是比喻承诺价值高，并非宣扬财富本身。","commonMistake":"望文生义，把“千金”理解成金钱主题。","memoryTip":"一诺千金，核心是重承诺。"}'::jsonb,2,true,1),
  ('culture-heritage-18','culture-calligraphy','culture-heritage-boss','single_choice','下列艺术常识表述正确的是？','{"questionId":"culture-heritage-18","knowledgeId":"culture-calligraphy","type":"single_choice","stem":"下列艺术常识表述正确的是？","options":[{"id":"A","text":"王羲之以《兰亭集序》著名"},{"id":"B","text":"吴道子被称为“书圣”"},{"id":"C","text":"小篆在唐朝统一文字时推行"},{"id":"D","text":"昆曲的四大行当为生旦净丑"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：王羲之以《兰亭集序》著名","whyCorrect":"王羲之与《兰亭集序》对应；吴道子为画圣，小篆在秦朝统一，生旦净丑是京剧行当。","whyUserAnswerWrong":"综合题要分别核对人物称号、书体时代和剧种属性。","commonMistake":"把不同艺术门类的关键词串用。","memoryTip":"兰亭王羲之，画圣吴道子，秦统一小篆。"}'::jsonb,3,true,1),
  ('culture-heritage-19','culture-festivals','culture-heritage-boss','single_choice','按农历日期先后，以下节日排列正确的是？','{"questionId":"culture-heritage-19","knowledgeId":"culture-festivals","type":"single_choice","stem":"按农历日期先后，以下节日排列正确的是？","options":[{"id":"A","text":"春节—端午—中秋—重阳"},{"id":"B","text":"端午—春节—重阳—中秋"},{"id":"C","text":"中秋—春节—端午—重阳"},{"id":"D","text":"重阳—中秋—端午—春节"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：春节—端午—中秋—重阳","whyCorrect":"春节在正月初一，端午在五月初五，中秋在八月十五，重阳在九月初九。","whyUserAnswerWrong":"按照农历月份排序，先抓月份再看具体日期。","commonMistake":"把中秋和重阳的先后顺序记反。","memoryTip":"一春、五端、八中、九重阳。"}'::jsonb,3,true,1),
  ('culture-heritage-20','culture-opera','culture-heritage-boss','single_choice','下列文化常识搭配正确的是？','{"questionId":"culture-heritage-20","knowledgeId":"culture-opera","type":"single_choice","stem":"下列文化常识搭配正确的是？","options":[{"id":"A","text":"昆曲—百戏之祖"},{"id":"B","text":"马头琴—苗族代表乐器"},{"id":"C","text":"曾侯乙编钟—唐代书法作品"},{"id":"D","text":"吴道子—《兰亭集序》作者"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：昆曲—百戏之祖","whyCorrect":"昆曲被誉为“百戏之祖”。马头琴对应蒙古族，曾侯乙编钟为礼乐器物，《兰亭集序》作者是王羲之。","whyUserAnswerWrong":"此题将剧种、乐器、器物和书法作品交叉设置，需逐项核对。","commonMistake":"把传统艺术放在同一类记忆，缺少具体对象对应。","memoryTip":"昆曲百戏祖，马头琴蒙古，兰亭王羲之。"}'::jsonb,3,true,1)
